// @kern-source: ansi-parse:122
export function hasAnsiCodes(text: string): boolean {
  return /\x1b\[/.test(text);
}

// @kern-source: ansi-parse:124
export function stripAnsi(text: string): string {
  return text.replace(/\x1b\[[0-9;]*m/g, '');
}
